# Redis queue utilities\nimport redis.asyncio as aioredis\nfrom core.redis import get_redis\n\nRAW_TX_QUEUE = 'raw_tx_queue'\nPARSED_TRADE_QUEUE = 'parsed_trade_queue'\nSIGNAL_EVAL_QUEUE = 'signal_eval_queue'\nHOLDER_UPDATE_QUEUE = 'holder_update_queue'\n\nasync def enqueue(queue_name: str, payload: str):\n    client = await get_redis()\n    await client.lpush(queue_name, payload)\n
